// Static-export build pipeline for hosting colorbyte-web on Render (non-Vercel).
//
// Next's `output: "export"` cannot build route handlers (src/app/api/**) or the
// dynamic sitemap route (src/app/sitemap.ts). Rather than editing those source
// files (esp. payment-adjacent ones), this orchestrator relocates them OUT of the
// app tree for the duration of the export build, then restores them. The static
// sitemap.xml is generated by copy-static-export-extensionless.mjs into out/.
//
// Usage:  NEXT_OUTPUT_EXPORT=1 is set automatically here.
//   node scripts/build-static-export.mjs
// Output: ./out  (static site to deploy to Render)
//
// NOTE: This does NOT touch checkout logic. The client creates checkout by calling
// the payment backend directly (colorbyte-api), so dropping the unused local
// /api/payment/dodo-create-checkout route has no runtime effect.

import { execSync } from "node:child_process";
import { renameSync, existsSync, mkdirSync, rmSync, writeFileSync } from "node:fs";
import path from "node:path";

const ROOT = process.cwd();
const STASH = path.join(ROOT, ".export-stash");

// Export-incompatible nodes (relative to repo root) -> stashed during build.
const RELOCATE = [
  "src/app/api",         // 4 route handlers (indexnow, keepalive, metrics/ga4, payment/dodo-create-checkout)
  "src/app/sitemap.ts",  // dynamic sitemap route; static sitemap.xml is generated post-build
];

function stashName(rel) {
  return path.join(STASH, rel.replace(/[/\\]/g, "__"));
}

function relocateOut() {
  if (existsSync(STASH)) rmSync(STASH, { recursive: true, force: true });
  mkdirSync(STASH, { recursive: true });
  for (const rel of RELOCATE) {
    const src = path.join(ROOT, rel);
    if (existsSync(src)) {
      renameSync(src, stashName(rel));
      console.log(`[stash] ${rel} -> .export-stash`);
    }
  }
}

function relocateBack() {
  for (const rel of RELOCATE) {
    const dst = path.join(ROOT, rel);
    const stashed = stashName(rel);
    if (existsSync(stashed)) {
      if (existsSync(dst)) rmSync(dst, { recursive: true, force: true });
      renameSync(stashed, dst);
      console.log(`[restore] ${rel}`);
    }
  }
  if (existsSync(STASH)) rmSync(STASH, { recursive: true, force: true });
}

function run(cmd) {
  console.log(`\n$ ${cmd}`);
  execSync(cmd, { stdio: "inherit", env: { ...process.env, NEXT_OUTPUT_EXPORT: "1", NEXT_TELEMETRY_DISABLED: "1" } });
}

let failed = false;
try {
  relocateOut();
  run("npx next build");
  run("node scripts/copy-static-export-extensionless.mjs");
  // DIAGNOSTIC (T167 feed.xml 404): Render retains no build logs, so capture
  // generate-rss's full stdout/stderr into the published out/ dir (proven to
  // publish — sitemap.xml lands here) as feed-build.log. Do NOT fail the build,
  // so the artifact + feed-debug.json always publish and can be curl'd.
  try {
    const rssOut = execSync("node scripts/generate-rss.mjs 2>&1", {
      encoding: "utf8",
      env: { ...process.env, NEXT_OUTPUT_EXPORT: "1", NEXT_TELEMETRY_DISABLED: "1" },
    });
    console.log(rssOut);
    writeFileSync(path.join(ROOT, "out", "feed-build.log"), rssOut, "utf8");
  } catch (e) {
    const captured = `${e.stdout || ""}${e.stderr || ""}\n[exit] ${e.message || e}`;
    console.error(captured);
    try {
      writeFileSync(path.join(ROOT, "out", "feed-build.log"), captured, "utf8");
    } catch (writeErr) {
      console.error("[rss] could not write feed-build.log:", writeErr?.message || writeErr);
    }
  }
  console.log("\n✓ static export complete -> ./out");
} catch (err) {
  failed = true;
  console.error("\n✗ static export build failed:", err?.message || err);
} finally {
  relocateBack(); // ALWAYS restore source, even on failure
}
process.exit(failed ? 1 : 0);
